sparql:
PREFIX al: <https://autoloan-docintel.example/ontology#>
SELECT ?ruleCode ?rootCode WHERE {
  ?rule al:ruleCode ?ruleCode .
  ?rule al:supersedes+ ?root .
  ?root al:ruleCode ?rootCode .
  FILTER NOT EXISTS { ?root al:supersedes ?older . }
}
ORDER BY ?ruleCode

PREFIX al: <https://autoloan-docintel.example/ontology#>
SELECT DISTINCT ?app WHERE {
  ?app a al:Application ;
       al:governedBy ?rule .
  ?rule al:appliesToRegion ?region .
  ?region al:regionName "Northeast" .
}
ORDER BY ?app

PREFIX al: <https://autoloan-docintel.example/ontology#>
SELECT ?app ?staleRuleCode WHERE {
  ?app a al:Application ;
       al:governedBy ?rule .
  ?rule al:ruleCode ?staleRuleCode .
  ?newer al:supersedes+ ?rule .
}
ORDER BY ?app

PREFIX al: <https://autoloan-docintel.example/ontology#>
SELECT ?borrower ?ficoBand WHERE {
  ?app a al:Application ;
       al:submittedBy ?borrower ;
       al:inRegion ?region .
  ?region al:regionName "Northeast" .
  ?borrower al:hasCreditProfile ?cp .
  ?cp al:ficoBand ?ficoBand .
}
ORDER BY ?borrower

PREFIX al: <https://autoloan-docintel.example/ontology#>
SELECT ?outcome ?ancestorCode WHERE {
  ?d a al:Decision ;
     al:decisionOutcome ?outcome ;
     al:derivedFrom ?rule .
  ?rule al:supersedes* ?ancestor .
  ?ancestor al:ruleCode ?ancestorCode .
}
ORDER BY ?outcome ?ancestorCode

PREFIX al: <https://autoloan-docintel.example/ontology#>
SELECT ?regionName (COUNT(DISTINCT ?rule) AS ?ruleCount) WHERE {
  ?rule a al:PolicyRule ;
        al:appliesToRegion ?region .
  ?region al:regionName ?regionName .
}
GROUP BY ?regionName
ORDER BY ?regionName

PREFIX al: <https://autoloan-docintel.example/ontology#>
SELECT ?app ?vehicleAge WHERE {
  ?app a al:Application ;
       al:hasCollateral ?v ;
       al:governedBy ?rule .
  ?v a al:Vehicle ;
     al:vehicleAge ?vehicleAge .
  FILTER(?vehicleAge > 5)
  ?rule al:appliesToRegion ?region .
  ?region al:regionName "Southeast" .
}
ORDER BY ?app
